// Get original form data from Prepare Input node
const prep = $('Prepare Input').first().json;
const headline     = prep.headline     || 'Unknown';
const source       = prep.source       || '';
const articleText  = String(prep.content || '');
const submitted_at = prep.submitted_at || new Date().toISOString();

// Get Gemini response
const gemini = $input.first().json;
const raw = gemini?.content?.parts?.[0]?.text
  || gemini?.text
  || gemini?.output
  || gemini?.candidates?.[0]?.content?.parts?.[0]?.text
  || '';

let parsed = {};
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    verdict: 'UNVERIFIABLE',
    confidence_score: 0,
    key_facts: 'Could not parse AI response: ' + raw.substring(0, 200),
    emotional_tone: 'unknown',
    manipulation_score: 0,
    manipulation_tactics: 'parse error',
    bias_detected: 'parse error',
    logical_issues: 'parse error',
    source_credibility: 'unknown',
    credibility_score: 0,
    red_flags: 'ai_parse_error',
    recommendation: 'Please re-submit the article for analysis.'
  };
}

return [{
  json: {
    submitted_at,
    headline,
    source,
    article_snippet:      articleText.substring(0, 300),
    verdict:              parsed.verdict              || 'UNVERIFIABLE',
    confidence_score:     parsed.confidence_score     ?? 0,
    key_facts:            parsed.key_facts            || '',
    logical_issues:       parsed.logical_issues       || 'none detected',
    red_flags:            parsed.red_flags            || 'none',
    recommendation:       parsed.recommendation       || '',
    emotional_tone:       parsed.emotional_tone       || 'unknown',
    manipulation_score:   parsed.manipulation_score   ?? 0,
    manipulation_tactics: parsed.manipulation_tactics || 'none',
    bias_detected:        parsed.bias_detected        || 'none detected',
    source_credibility:   parsed.source_credibility   || 'unknown',
    credibility_score:    parsed.credibility_score    ?? 0
  }
}];
